"use client";

import { useRouter } from "next/navigation";

import { useAuth } from "../../../features/auth/components/auth-provider";

const overviewCards = [
  {
    eyebrow: "Guest Ready",
    title: "课程视频",
    copy: "游客可直接进入课程导览与视频预览区，不需要先登录。",
    action: "进入观看",
    kind: "open-video",
  },
  {
    eyebrow: "Login Required",
    title: "知识图谱",
    copy: "点击知识节点、查看关系联动和推荐路径前，需要先完成登录。",
    action: "打开图谱",
    kind: "open-graph",
  },
  {
    eyebrow: "Login Required",
    title: "AI 助学",
    copy: "向 AI 助教发起提问、查看会话历史和数字人语音回复时，需要登录。",
    action: "发起提问",
    kind: "open-ai",
  },
];

export default function OverviewPage() {
  const router = useRouter();
  const { isAuthenticated, openAuthModal } = useAuth();

  const handleProtectedAction = (reason: string, href: string) => {
    if (isAuthenticated) {
      router.push(href);
      return;
    }

    openAuthModal({
      mode: "login",
      reason,
    });
  };

  return (
    <section className="platform-panel">
      <header className="platform-page-header">
        <div className="eyebrow">Overview</div>
        <h2 className="page-title">教学导览</h2>
        <p className="page-description">
          这一页承担游客的首屏浏览入口。用户可以直接查看课程导览和视频区；当点击
          AI 助学、知识图谱等需要身份能力的入口时，再通过登录弹窗继续。
        </p>
      </header>

      <section className="overview-hero">
        <div className="overview-hero-copy">
          <div className="eyebrow">Learning Route</div>
          <h3 className="section-title">先浏览，再登录继续深度互动</h3>
          <p className="body-copy">
            游客模式下可直接了解课程结构、章节路径和视频区域。登录后，平台会继续开放
            AI 对话、知识图谱交互、实训记录和学习进度保存。
          </p>
        </div>

        <div className="overview-hero-actions">
          <button
            className="button-primary"
            type="button"
            onClick={() => router.push("/course")}
          >
            查看课程视频
          </button>
          <button
            className="button-secondary"
            type="button"
            onClick={() =>
              openAuthModal({
                mode: "login",
                reason: "登录后即可继续使用 AI 助学、知识图谱与实训能力。",
              })
            }
          >
            登录后解锁完整能力
          </button>
        </div>
      </section>

      <section className="section-block">
        <h3 className="section-title">入口权限</h3>
        <div className="route-grid">
          {overviewCards.map((card) => (
            <article key={card.title} className="route-card">
              <div>
                <div className="eyebrow">{card.eyebrow}</div>
                <div className="route-name">{card.title}</div>
                <p className="route-copy">{card.copy}</p>
              </div>

              {card.kind === "open-video" ? (
                <button
                  className="route-link"
                  type="button"
                  onClick={() => router.push("/course")}
                >
                  {card.action}
                </button>
              ) : card.kind === "open-graph" ? (
                <button
                  className="route-link"
                  type="button"
                  onClick={() =>
                    handleProtectedAction(
                      "打开知识图谱前请先登录。",
                      "/overview",
                    )
                  }
                >
                  {card.action}
                </button>
              ) : (
                <button
                  className="route-link"
                  type="button"
                  onClick={() =>
                    handleProtectedAction("向 AI 助学提问前请先登录。", "/assistant")
                  }
                >
                  {card.action}
                </button>
              )}
            </article>
          ))}
        </div>
      </section>
    </section>
  );
}
